mkdir -p /tmp/friday13 && cat > /tmp/friday13/friday13.cs << 'EOF'
Console.WriteLine("=== Earliest Friday the 13th (Proleptic Gregorian) ===");

var date = new DateTime(1, 1, 13); // start checking the 13th of each month
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date:dddd})");

Console.WriteLine();
Console.WriteLine("=== Friday the 13ths in a 400-year cycle (0001–0400) ===");

int count = 0;
var current = new DateTime(1, 1, 13);
var end = new DateTime(401, 1, 1);

while (current < end)
{
    if (current.DayOfWeek == DayOfWeek.Friday)
        count++;
    current = current.AddMonths(1);
}

Console.WriteLine($"Total Friday the 13ths in 400 years: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// Bonus: distribution by month
Console.WriteLine();
Console.WriteLine("=== Distribution by Month ===");
var monthlyCounts = new int[12];
current = new DateTime(1, 1, 13);
while (current < end)
{
    if (current.DayOfWeek == DayOfWeek.Friday)
        monthlyCounts[current.Month - 1]++;
    current = current.AddMonths(1);
}

for (int m = 0; m < 12; m++)
    Console.WriteLine($"  {new DateTime(2000, m + 1, 1):MMMM,-10}: {monthlyCounts[m]}");
EOF
